void bfs(unordered_map<int, vector<int>>& graph, int start) {
    queue<int> q;
    unordered_set<int> visited;
    q.push(start);
    visited.insert(start);
    while (!q.empty()) {
        int node = q.front();
        q.pop();
        cout << node << " ";
        for (int nbr : graph[node]) {
            if (!visited.count(nbr)) {
                visited.insert(nbr);
                q.push(nbr);
            }
        }
    }
}

